    // MARK: - Network Request
    
    private func performPasswordReset(token: String, newPassword: String) {
        setLoadingState(true)
        
        guard let url = URL(string: "https://api.myapp.com/v1/auth/reset-password") else {
            showError("Invalid server configuration")
            setLoadingState(false)
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.timeoutInterval = 30
        
        let body: [String: String] = [
            "token": token,
            "new_password": newPassword
        ]
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: body)
        } catch {
            showError("Failed to prepare request")
            setLoadingState(false)
            return
        }
        
        URLSession.shared.dataTask(with: request) { [weak self] data, response, error in
            DispatchQueue.main.async {
                self?.setLoadingState(false)
                
                if let error = error {
                    self?.showError("Network error: \(error.localizedDescription)")
                    return
                }
                
                guard let httpResponse = response as? HTTPURLResponse else {
                    self?.showError("Invalid server response")
                    return
                }
                
                switch httpResponse.statusCode {
                case 200:
                    self?.showSuccess()
                case 400:
                    self?.showError("Invalid or expired reset token. Please request a new password reset link.")
                case 401:
                    self?.showError("This reset link has expired. Please request a new one.")
                case 422:
                    if let data = data,
                       let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                       let message = json["message"] as? String {
                        self?.showError(message)
                    } else {
                        self?.showError("Password does not meet requirements")
                    }
                case 429:
                    self?.showError("Too many attempts. Please try again later.")
                default:
                    self?.showError("Something went wrong. Please try again.")
                }
            }
        }.resume()
    }
    
    private func setLoadingState(_ isLoading: Bool) {
        if isLoading {
            activityIndicator.startAnimating()
        } else {
            activityIndicator.stopAnimating()
        }
        
        resetButton.isEnabled = !isLoading
        newPasswordTextField.isEnabled = !isLoading
        confirmPasswordTextField.isEnabled = !isLoading
        view.isUserInteractionEnabled = !isLoading || true
    }
    
    private func showError(_ message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func showSuccess() {
        let alert = UIAlertController(
            title: "Password Reset Successful",
            message: "Your password has been updated. You can now log in with your new password.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Log In", style: .default) { [weak self] _ in
            self?.navigateToLogin()
        })
        present(alert, animated: true)
    }
    
    private func navigateToLogin() {
        dismiss(animated: true) {
            NotificationCenter.default.post(name: .passwordResetCompleted, object: nil)
        }
    }
