// MARK: - SceneDelegate Integration

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        window = UIWindow(windowScene: windowScene)
        window?.rootViewController = createMainViewController()
        window?.makeKeyAndVisible()
        
        // Handle universal link from cold launch
        if let urlContext = connectionOptions.urlContexts.first {
            handleIncomingURL(urlContext.url)
        }
        
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            handleIncomingURL(url)
        }
        
        DeepLinkNavigationCoordinator.shared.delegate = self
        DeepLinkNavigationCoordinator.shared.markAppReady()
    }
    
    // Handle universal link when app is already running
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        handleIncomingURL(url)
    }
    
    // Handle URL scheme
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        guard let url = URLContexts.first?.url else { return }
        handleIncomingURL(url)
    }
    
    private func handleIncomingURL(_ url: URL) {
        _ = DeepLinkNavigationCoordinator.shared.handleUniversalLink(url)
    }
    
    private func createMainViewController() -> UIViewController {
        // Placeholder - replace with your actual main view controller
        let vc = UIViewController()
        vc.view.backgroundColor = .systemBackground
        return UINavigationController(rootViewController: vc)
    }
    
    private func presentPasswordResetScreen(with deepLink: PasswordResetDeepLink) {
        guard let rootViewController = window?.rootViewController else { return }
        
        // Dismiss any currently presented view controllers
        rootViewController.dismiss(animated: false) {
            let passwordResetVC = PasswordResetViewController(deepLink: deepLink)
            let navController = UINavigationController(rootViewController: passwordResetVC)
            navController.modalPresentationStyle = .fullScreen
            rootViewController.present(navController, animated: true)
        }
    }
}

// MARK: - SceneDelegate + NavigationCoordinatorDelegate

extension SceneDelegate: NavigationCoordinatorDelegate {
    func coordinatorDidRequestPasswordReset(with deepLink: PasswordResetDeepLink) {
        presentPasswordResetScreen(with: deepLink)
    }
    
    func coordinatorDidEncounterInvalidLink() {
        showAlert(title: "Invalid Link", message: "This link is invalid or has been corrupted. Please request a new password reset link.")
    }
    
    func coordinatorDidEncounterExpiredLink() {
        showAlert(title: "Link Expired", message: "This password reset link has expired. Please request a new one.")
    }
    
    private func showAlert(title: String, message: String) {
        guard let rootViewController = window?.rootViewController else { return }
        
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        
        let presenter = rootViewController.presentedViewController ?? rootViewController
        presenter.present(alert, animated: true)
    }
}

// MARK: - AppDelegate (for iOS 12 and earlier or apps not using scenes)

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        return true
    }
    
    // MARK: UISceneSession Lifecycle
    
    func application(_ application: UIApplication, configurationForConnecting connectingSceneSession: UISceneSession, options: UIScene.ConnectionOptions) -> UISceneConfiguration {
        return UISceneConfiguration(name: "Default Configuration", sessionRole: connectingSceneSession.role)
    }
    
    // For apps not using UIScene (iOS 12 and below)
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        return DeepLinkNavigationCoordinator.shared.handleUniversalLink(url)
    }
}